diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index a9c764588faa1..09dc990456223 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -1786,10 +1786,6 @@ Instruction *InstCombinerImpl::foldICmpAndConstConst(ICmpInst &Cmp,
                                                      const APInt &C1) {
   bool isICMP_NE = Cmp.getPredicate() == ICmpInst::ICMP_NE;

-  // icmp ne (and X, 1), 0 --> trunc X to i1
-  if (isICMP_NE && C1.isZero() && match(And->getOperand(1), m_One()))
-    return new TruncInst(And->getOperand(0), Cmp.getType());
-
   const APInt *C2;
   Value *X;
   if (!match(And, m_And(m_Value(X), m_APInt(C2))))
@@ -7088,6 +7084,12 @@ Instruction *InstCombinerImpl::foldICmpUsingKnownBits(ICmpInst &I) {
           *LHSC != Op0KnownZeroInverted)
         LHS = Op0;

+      if (Pred == CmpInst::ICMP_NE && Ty->isIntOrIntVectorTy() &&
+          Op0Known.getMaxValue() == 1)
+        return replaceInstUsesWith(I,
+                                   Builder.CreateTrunc(LHS, I.getType(), "",
+                                                       /*IsNUW=*/LHS == Op0));
+
       Value *X;
       const APInt *C1;
       if (match(LHS, m_Shl(m_Power2(C1), m_Value(X)))) {

tests.test_body:
define i1 @and_icmp_ne_with_binary_range_operands(i8 range(i8 0, 2) %x, i8 range(i8 0, 2) %y) {
  %icmp1 = icmp ne i8 %x, 0
  %icmp2 = icmp ne i8 %y, 0
  %ret = and i1 %icmp1, %icmp2
  ret i1 %ret
}

define i1 @and_icmp_eq_with_binary_range_operands(i8 range(i8 0, 2) %x, i8 range(i8 0, 2) %y) {
  %icmp1 = icmp eq i8 %x, 1
  %icmp2 = icmp eq i8 %y, 1
  %ret = and i1 %icmp1, %icmp2
  ret i1 %ret
}

define i1 @icmp_eq_bool_1(ptr %ptr) {
  %val = load i64, ptr %ptr, align 8, !range !0
  %cmp = icmp eq i64 %val, 1
  ret i1 %cmp
}

!0 = !{i64 0, i64 2}

define i1 @icmp_ne_bool_0(ptr %ptr) {
  %val = load i64, ptr %ptr, align 8, !range !0
  %cmp = icmp ne i64 %val, 0
  ret i1 %cmp
}

!0 = !{i64 0, i64 2}

define i1 @icmp_eq_bool_0(ptr %ptr) {
  %val = load i64, ptr %ptr, align 8, !range !0
  %cmp = icmp eq i64 %val, 0
  ret i1 %cmp
}

!0 = !{i64 0, i64 2}

define i1 @lshrugt_02_15_exact(i4 %x) {
  %s = lshr exact i4 %x, 2
  %c = icmp ugt i4 %s, -1
  ret i1 %c
}

define i1 @lshrugt_03_00_exact(i4 %x) {
  %s = lshr exact i4 %x, 3
  %c = icmp ugt i4 %s, 0
  ret i1 %c
}

define i1 @icmp_eq_multiuse_negative(i8 %arg) {
  %sub = call i8 @llvm.usub.sat.i8(i8 %arg, i8 -2)
  %cmp = icmp eq i8 %sub, 1
  call void @use.i8(i8 %sub)
  ret i1 %cmp
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare i8 @llvm.usub.sat.i8(i8, i8) #0

declare void @use.i8(i8)

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(none) }

define zeroext i1 @_Z3fooPb(ptr nocapture %x) {
entry:
  %a = load i8, ptr %x, align 1, !range !0
  %b = and i8 %a, 1
  %tobool = icmp ne i8 %b, 0
  ret i1 %tobool
}

!0 = !{i8 0, i8 2}

